// --- types.d.ts ---
/**
 * Represents a single day's weather forecast.
 */
export interface ForecastDay {
  /** Day of the week (e.g., "Mon") */
  day: string;
  /** Icon identifier or emoji representing the weather condition */
  icon: string;
  /** Maximum temperature for the day */
  high: number;
  /** Minimum temperature for the day */
  low: number;
}

/**
 * Props for the main WeatherCard component.
 */
export interface WeatherCardProps {
  /** Name of the city */
  city: string;
  /** Current temperature value */
  temperature: number;
  /** Description of current weather (e.g., "Partly Cloudy") */
  condition: string;
  /** Humidity percentage (0-100) */
  humidity: number;
  /** Wind speed value */
  windSpeed: number;
  /** Temperature unit, defaults to "C" or "F" */
  unit?: "C" | "F" | string;
  /** Array of forecast data for upcoming days */
  forecast: ForecastDay[];
}

/**
 * Props for the current weather display sub-component.
 */
export interface CurrentWeatherProps {
  /** Formatted temperature string (e.g., "21°") */
  temperature: string;
  /** Current weather condition description */
  condition: string;
  /** Mapped icon for the current condition */
  conditionIcon: string;
  /** City name */
  city: string;
}

/**
 * Props for displaying secondary weather statistics.
 */
export interface WeatherStatsProps {
  /** Humidity percentage */
  humidity: number;
  /** Formatted wind speed string including units (e.g., "12 km/h") */
  windSpeed: string;
}

/**
 * Props for the horizontal forecast display.
 */
export interface ForecastStripProps {
  /** Array of forecast data */
  forecast: ForecastDay[];
  /** Unit symbol for temperature (e.g., "°C") */
  unit: string;
}

/**
 * Return type for the weather data processing hook.
 */
export interface UseWeatherReturn {
  /** Temperature with unit symbol */
  formattedTemp: string;
  /** Wind speed with units (e.g., "km/h" or "mph") */
  formattedWind: string;
  /** The symbol for the degree unit (e.g., "°C") */
  displayUnit: string;
  /** Mapped icon based on weather condition */
  conditionIcon: string;
  /** Screen-reader friendly summary of current weather */
  accessibleLabel: string;
}


// --- constants.ts ---
// constants.ts — static data, mappings, configurations

/**
 * Mapping of weather conditions to emoji icons.
 */
export const WEATHER_CONDITION_MAP = {
  Sunny: "☀️",
  Clear: "☀️",
  "Partly Cloudy": "⛅",
  Cloudy: "☁️",
  Overcast: "☁️",
  Rain: "🌧️",
  Drizzle: "🌦️",
  Thunderstorm: "⛈️",
  Snow: "❄️",
  Mist: "🌫️",
  Fog: "🌫️",
} as const;

/**
 * Fallback icon for unknown weather conditions.
 */
export const FALLBACK_ICON = "❓" as const;

/**
 * Default temperature unit.
 */
export const DEFAULT_UNIT = "C" as const;

/**
 * Mapping of unit keys to their display symbols.
 */
export const UNIT_SYMBOLS = {
  C: "°C",
  F: "°F",
} as const;

/**
 * Mapping of unit systems to wind speed unit strings.
 */
export const WIND_SPEED_UNITS = {
  metric: "km/h",
  imperial: "mph",
} as const;

/**
 * Descriptive labels for screen readers based on weather conditions.
 */
export const CONDITION_ACCESSIBILITY_LABELS: Record<string, string> = {
  Sunny: "Sunny with clear skies",
  Clear: "Clear skies",
  "Partly Cloudy": "Partly cloudy with some sun",
  Cloudy: "Cloudy skies",
  Overcast: "Overcast and grey",
  Rain: "Rainy with precipitation",
  Drizzle: "Light drizzle and mist",
  Thunderstorm: "Thunderstorms with heavy rain and lightning",
  Snow: "Snowy with winter precipitation",
  Mist: "Misty and low visibility",
  Fog: "Foggy with very low visibility",
} as const;


// --- hooks.ts ---
// hooks.ts — state, handlers, data transformations
import { useMemo } from 'react';
import type { WeatherCardProps, UseWeatherReturn } from './types';

export function useWeather(props: WeatherCardProps): UseWeatherReturn {
  const {
    city,
    temperature,
    condition,
    windSpeed,
    unit = 'C',
  } = props;

  return useMemo(() => {
    const isFahrenheit = unit === 'F';
    const displayUnit = isFahrenheit ? '°F' : '°C';
    const unitFullName = isFahrenheit ? 'Fahrenheit' : 'Celsius';

    // 1. Unit Handling
    const roundedTemp = Math.round(temperature);
    const formattedTemp = `${roundedTemp}${displayUnit}`;

    // 2. Wind Speed Formatting
    const windUnit = isFahrenheit ? 'mph' : 'km/h';
    const formattedWind = `${windSpeed} ${windUnit}`;

    // 3. Condition Icon Mapping
    let conditionIcon = '☁️'; // Default
    const normalizedCondition = condition.toLowerCase();

    if (normalizedCondition.includes('sunny') || normalizedCondition.includes('clear')) {
      conditionIcon = '☀️';
    } else if (normalizedCondition.includes('cloudy')) {
      conditionIcon = '☁️';
    } else if (normalizedCondition.includes('rain') || normalizedCondition.includes('showers')) {
      conditionIcon = '🌧️';
    } else if (normalizedCondition.includes('snow')) {
      conditionIcon = '❄️';
    } else if (normalizedCondition.includes('thunderstorm')) {
      conditionIcon = '⛈️';
    }

    // 4. Accessibility
    // Format: "Current weather in {city}: {temperature} degrees {unit}, {condition}."
    const accessibleLabel = `Current weather in ${city}: ${roundedTemp} degrees ${unitFullName}, ${condition}.`;

    return {
      formattedTemp,
      formattedWind,
      displayUnit,
      conditionIcon,
      accessibleLabel,
    };
  }, [city, temperature, condition, windSpeed, unit]);
}


