// components/CurrentWeather.tsx — reusable sub-component
import React from 'react';
import { Stack, Text, Heading } from '@ggui-ai/design/primitives';
import type { CurrentWeatherProps } from './types';

/**
 * CurrentWeather component displays the main weather overview for a specific city.
 * It follows the design system guidelines for spacing, typography, and accessibility.
 */
export function CurrentWeather({ temperature, condition, conditionIcon, city }: CurrentWeatherProps) {
  return (
    <div
      aria-label={`Current weather in ${city}: ${temperature}, ${condition}`}
      style={{
        paddingTop: 'var(--ggui-spacing-6, 24px)',
        width: '100%',
      }}
    >
      <Stack align="center" gap="var(--ggui-spacing-2, 8px)">
        {/* City Name */}
        <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
          {city}
        </Heading>

        {/* Temperature and Condition Icon */}
        <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-4, 16px)">
          <span
            role="img"
            aria-label={condition}
            style={{
              fontSize: 'var(--ggui-font-size-4xl, 36px)',
              lineHeight: 1,
            }}
          >
            {conditionIcon}
          </span>
          <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
            {temperature}
          </Heading>
        </Stack>

        {/* Condition Description */}
        <Text
          variant="bodyLarge"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
          align="center"
        >
          {condition}
        </Text>
      </Stack>
    </div>
  );
}


// --- components/WeatherStats.tsx ---
// components/WeatherStats.tsx — reusable sub-component
import React from 'react';
import { Stack, Text, Divider, Box } from '@ggui-ai/design/primitives';
import type { WeatherStatsProps } from './types';

/**
 * WeatherStats displays detailed metrics for current weather conditions.
 *
 * It uses a horizontal layout to present humidity and wind speed,
 * separated by a vertical divider for visual clarity.
 *
 * @param props - Humidity (number) and Wind Speed (string)
 */
export function WeatherStats({ humidity, windSpeed }: WeatherStatsProps) {
  return (
    <Box>
      <div aria-label="Weather details">
        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-6)"
          align="center"
          justify="start"
        >
          {/* Humidity Stat */}
          <Stack gap="var(--ggui-spacing-1)" align="start">
            <Text
              variant="label"
              color="var(--ggui-color-onSurfaceVariant)"
            >
              Humidity
            </Text>
            <Text
              variant="bodyLarge"
              color="var(--ggui-color-onSurface)"
            >
              {humidity}%
            </Text>
          </Stack>

          {/* Vertical Divider */}
          <Divider orientation="vertical" margin={0} />

          {/* Wind Speed Stat */}
          <Stack gap="var(--ggui-spacing-1)" align="start">
            <Text
              variant="label"
              color="var(--ggui-color-onSurfaceVariant)"
            >
              Wind
            </Text>
            <Text
              variant="bodyLarge"
              color="var(--ggui-color-onSurface)"
            >
              {windSpeed}
            </Text>
          </Stack>
        </Stack>
      </div>
    </Box>
  );
}


// --- components/ForecastStrip.tsx ---
import React from 'react';
import { Row, Stack, Text, Icon } from '@ggui-ai/design/primitives';
import type { ForecastStripProps } from '../types';

/**
 * ForecastStrip component displays a horizontal row of daily weather forecasts.
 */
export function ForecastStrip({ forecast, unit }: ForecastStripProps) {
  return (
    <div 
      aria-label="5-day forecast" 
      style={{ 
        width: '100%',
        overflowX: 'auto',
        WebkitOverflowScrolling: 'touch',
        padding: '0 var(--ggui-spacing-4)'
      }}
    >
      {/* Outer container: Row with justify="space-between", align="center", and gap={4} */}
      <Row 
        justify="between" 
        align="center" 
        gap={4}
      >
        {forecast.map((day, index) => (
          <Stack 
            key={`${day.day}-${index}`} 
            align="center" 
            gap={1}
            style={{ minWidth: 'fit-content' }}
          >
            {/* Day Label */}
            <Text 
              variant="label" 
              color="var(--ggui-color-onSurfaceVariant)"
            >
              {day.day}
            </Text>

            {/* Weather Icon: pass icon string to name prop and add aria-label */}
            <span role="img" aria-label={`Weather condition: ${day.icon}`}>
              <Icon name={day.icon} size={24} />
            </span>

            {/* Temperatures: Row with gap={2} */}
            <Row gap={2} align="center">
              {/* High Temp */}
              <Text variant="bodySmall" weight="bold">
                {day.high}{unit}
              </Text>

              {/* Low Temp */}
              <Text 
                variant="bodySmall" 
                color="var(--ggui-color-onSurfaceVariant)"
              >
                {day.low}{unit}
              </Text>
            </Row>
          </Stack>
        ))}
      </Row>
    </div>
  );
}


// --- ui.tsx ---
// ui.tsx — main visual layout, design system primitives
import React from 'react';
import { 
  Card, 
  Stack, 
  Box, 
  Divider, 
  Container 
} from '@ggui-ai/design/primitives';
import type { WeatherCardProps, UseWeatherReturn } from './types';
import { CurrentWeather, WeatherStats, ForecastStrip } from './components';

export function ComponentUI(props: WeatherCardProps & UseWeatherReturn) {
  const {
    city,
    condition,
    humidity,
    forecast,
    formattedTemp,
    formattedWind,
    displayUnit,
    conditionIcon,
  } = props;

  return (
    <Container maxWidth="450px" padding={0} center>
      <Card 
        padding="var(--ggui-spacing-6, 24px)" 
        shadow="md" 
        radius="xl"
        border
      >
        <Stack gap="var(--ggui-spacing-6, 24px)">
          {/* Section A: Current Weather Header */}
          <Box>
            <CurrentWeather
              city={city}
              temperature={formattedTemp}
              condition={condition}
              conditionIcon={conditionIcon}
            />
          </Box>

          <Divider margin={0} />

          {/* Section B: Weather Details (Stats) */}
          <Box>
            <WeatherStats
              humidity={humidity}
              windSpeed={formattedWind}
            />
          </Box>

          <Divider margin={0} />

          {/* Section C: Forecast Strip */}
          <Box>
            <ForecastStrip
              forecast={forecast}
              unit={displayUnit}
            />
          </Box>
        </Stack>
      </Card>
    </Container>
  );
}


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
